import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ExamConfig, ExamData, CognitiveLevel } from "../types";

// Define the response schema strictly to ensure valid JSON output
const examSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "Tên đề thi, ví dụ: Đề kiểm tra 1 tiết Lịch sử 12 - [Chủ đề]" },
    multipleChoice: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Mảng gồm 4 nội dung lựa chọn. CHỈ GHI NỘI DUNG CÂU TRẢ LỜI. TUYỆT ĐỐI KHÔNG GHI KÝ TỰ 'A.', 'B.', 'C.', 'D.' Ở ĐẦU."
          },
          correctAnswer: { type: Type.STRING, description: "Chỉ ghi A, B, C hoặc D" },
          level: { type: Type.STRING, description: "Mức độ nhận thức (Nhận biết, Thông hiểu, Vận dụng, Vận dụng cao)" }
        },
        required: ["question", "options", "correctAnswer", "level"]
      }
    },
    essay: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          rubric: { type: Type.STRING, description: "Hướng dẫn chấm/đáp án ngắn gọn" },
          level: { type: Type.STRING }
        },
        required: ["question", "rubric", "level"]
      }
    }
  },
  required: ["title", "multipleChoice", "essay"]
};

export const generateExam = async (config: ExamConfig): Promise<ExamData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const distributionText = Object.entries(config.distribution)
    .map(([level, percent]) => `- ${level}: ${percent}%`)
    .join('\n');

  const prompt = `
    Đóng vai một giáo viên Lịch sử chuyên nghiệp tại Trường THCS Phương Lâm, có kinh nghiệm ra đề thi chuẩn theo quy định.
    Hãy soạn một đề thi môn Lịch sử với các yêu cầu sau:

    1. **Chủ đề:** ${config.topic}
    2. **Đối tượng:** Học sinh ${config.grade}
    3. **Cấu trúc đề thi:**
       - Phần 1: ${config.mcCount} câu trắc nghiệm khách quan (4 lựa chọn).
       - Phần 2: ${config.essayCount} câu tự luận.
    4. **Ma trận nhận thức (Phân bố mức độ khó):**
       ${distributionText}

    **Yêu cầu quan trọng về định dạng (Format):**
    - **TUYỆT ĐỐI KHÔNG** thêm các ký tự đánh số thứ tự như "A.", "B.", "C.", "D." hoặc "1.", "2." vào đầu nội dung của các phương án trắc nghiệm trong JSON. Hệ thống hiển thị sẽ tự động thêm vào.
    - Ví dụ SAI: "A. Chiến thắng Bạch Đằng"
    - Ví dụ ĐÚNG: "Chiến thắng Bạch Đằng"

    **Yêu cầu về nội dung:**
    - Văn phong chuẩn mực, sư phạm, nghiêm túc.
    - Câu hỏi trắc nghiệm phải có tính nhiễu tốt, không quá dễ đoán.
    - Câu hỏi tự luận phải kích thích tư duy, phù hợp với mức độ Vận dụng và Vận dụng cao.
    - Đảm bảo chính xác về kiến thức lịch sử.
    - Nội dung câu hỏi phải tuân thủ đúng tỷ lệ phần trăm mức độ nhận thức đã yêu cầu.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Switched to Flash to save cost and increase speed
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: examSchema,
        thinkingConfig: { thinkingBudget: 1024 } // Flash supports thinking with smaller budget for efficiency
      }
    });

    const text = response.text;
    if (!text) throw new Error("Không nhận được dữ liệu từ Gemini.");

    const rawData = JSON.parse(text);

    // Map raw data to our typed structure with IDs
    const examData: ExamData = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config: config,
      title: rawData.title,
      multipleChoice: rawData.multipleChoice.map((q: any) => ({ ...q, id: crypto.randomUUID() })),
      essay: rawData.essay.map((q: any) => ({ ...q, id: crypto.randomUUID() }))
    };

    return examData;

  } catch (error) {
    console.error("Lỗi khi tạo đề:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { ExamConfig, CognitiveLevel } from '../types';
import { Loader2, Wand2 } from 'lucide-react';

interface Props {
  onGenerate: (config: ExamConfig) => void;
  isGenerating: boolean;
}

const DEFAULT_CONFIG: ExamConfig = {
  topic: '',
  grade: 'Lớp 9',
  mcCount: 20,
  essayCount: 2,
  distribution: {
    [CognitiveLevel.NHAN_BIET]: 40,
    [CognitiveLevel.THONG_HIEU]: 30,
    [CognitiveLevel.VAN_DUNG]: 20,
    [CognitiveLevel.VAN_DUNG_CAO]: 10,
  }
};

export const ExamConfigForm: React.FC<Props> = ({ onGenerate, isGenerating }) => {
  const [config, setConfig] = useState<ExamConfig>(DEFAULT_CONFIG);

  const totalPercent = Object.values(config.distribution).reduce((a: number, b: number) => a + b, 0);

  const handleDistributionChange = (level: CognitiveLevel, value: number) => {
    setConfig(prev => ({
      ...prev,
      distribution: {
        ...prev.distribution,
        [level]: value
      }
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (totalPercent !== 100) {
      alert(`Tổng phần trăm các mức độ phải bằng 100%. Hiện tại: ${totalPercent}%`);
      return;
    }
    if (!config.topic.trim()) {
      alert("Vui lòng nhập chủ đề kiểm tra.");
      return;
    }
    onGenerate(config);
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
      <div className="flex items-center gap-2 mb-6 text-edu-900">
        <Wand2 className="w-6 h-6" />
        <h2 className="text-xl font-bold">Thiết lập Đề thi</h2>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Topic & Grade */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="md:col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Chủ đề / Nội dung kiến thức</label>
            <input
              type="text"
              required
              placeholder="Ví dụ: Cách mạng tháng Tám năm 1945"
              className="w-full px-4 py-2 bg-white text-gray-900 border border-gray-300 rounded-lg focus:ring-2 focus:ring-edu-500 focus:border-edu-500 outline-none transition"
              value={config.topic}
              onChange={e => setConfig({ ...config, topic: e.target.value })}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Khối Lớp</label>
            <select
              className="w-full px-4 py-2 bg-white text-gray-900 border border-gray-300 rounded-lg focus:ring-2 focus:ring-edu-500 outline-none"
              value={config.grade}
              onChange={e => setConfig({ ...config, grade: e.target.value })}
            >
              <option value="Lớp 6">Lớp 6</option>
              <option value="Lớp 7">Lớp 7</option>
              <option value="Lớp 8">Lớp 8</option>
              <option value="Lớp 9">Lớp 9</option>
            </select>
          </div>
        </div>

        {/* Question Counts */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Số câu Trắc nghiệm</label>
            <input
              type="number"
              min="0"
              max="50"
              className="w-full px-4 py-2 bg-white text-gray-900 border border-gray-300 rounded-lg focus:ring-2 focus:ring-edu-500 outline-none"
              value={config.mcCount}
              onChange={e => setConfig({ ...config, mcCount: parseInt(e.target.value) || 0 })}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Số câu Tự luận</label>
            <input
              type="number"
              min="0"
              max="10"
              className="w-full px-4 py-2 bg-white text-gray-900 border border-gray-300 rounded-lg focus:ring-2 focus:ring-edu-500 outline-none"
              value={config.essayCount}
              onChange={e => setConfig({ ...config, essayCount: parseInt(e.target.value) || 0 })}
            />
          </div>
        </div>

        {/* Cognitive Matrix */}
        <div className="p-4 bg-gray-50 rounded-lg border border-gray-200">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-semibold text-gray-800">Ma trận nhận thức</h3>
            <span className={`text-sm font-bold ${totalPercent === 100 ? 'text-green-600' : 'text-red-500'}`}>
              Tổng: {totalPercent}%
            </span>
          </div>

          <div className="space-y-4">
            {Object.values(CognitiveLevel).map((level) => (
              <div key={level} className="flex items-center gap-4">
                <label className="w-32 text-sm text-gray-600 font-medium">{level}</label>
                <input
                  type="range"
                  min="0"
                  max="100"
                  step="5"
                  className="flex-1 h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-edu-600"
                  value={config.distribution[level]}
                  onChange={e => handleDistributionChange(level, parseInt(e.target.value))}
                />
                <span className="w-12 text-sm font-bold text-gray-700 text-right">{config.distribution[level]}%</span>
              </div>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={isGenerating}
          className="w-full py-3 bg-edu-600 hover:bg-edu-700 text-white font-semibold rounded-lg shadow-md transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
        >
          {isGenerating ? (
            <>
              <Loader2 className="animate-spin w-5 h-5" />
              Đang phân tích và tạo đề (Gemini 3.0 Flash)...
            </>
          ) : (
            <>
              <Wand2 className="w-5 h-5" />
              Tạo Đề Thi Ngay
            </>
          )}
        </button>
      </form>
    </div>
  );
};

